import{_ as e,o as r,c as l,a2 as t}from"./chunks/framework.ZhLefgN8.js";const b=JSON.parse('{"title":"新加坡股票转仓","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"stock-trading/stock-transfer/sg-transfer.md","filePath":"zh-CN/stock-trading/stock-transfer/sg-transfer.md"}'),i={name:"stock-trading/stock-transfer/sg-transfer.md"};function o(n,a,h,s,c,d){return r(),l("div",null,[...a[0]||(a[0]=[t('<h1 id="新加坡股票转仓" tabindex="-1">新加坡股票转仓 <a class="header-anchor" href="#新加坡股票转仓" aria-label="Permalink to &quot;新加坡股票转仓&quot;">​</a></h1><p>股票转仓（又称转户）是将在一家券商持有的股票转移到另一家券商证券账户的过程，支持转入和转出。仅支持本人同名账户间转仓。</p><h2 id="支持品类" tabindex="-1">支持品类 <a class="header-anchor" href="#支持品类" aria-label="Permalink to &quot;支持品类&quot;">​</a></h2><p>香港市场：股票、ETF<br> 美国市场：股票、ETF<br> 新加坡市场：股票</p><h2 id="收费标准" tabindex="-1">收费标准 <a class="header-anchor" href="#收费标准" aria-label="Permalink to &quot;收费标准&quot;">​</a></h2><p>转入长桥免费，转出券商可能收费，请与对方确认。<br> 转出收费请参考长桥官网公布的标准。注：转出费用将由新加坡政府征收 9% 的商品及服务税（GST，如适用）。</p><h2 id="转仓信息" tabindex="-1">转仓信息 <a class="header-anchor" href="#转仓信息" aria-label="Permalink to &quot;转仓信息&quot;">​</a></h2><hr><h2 id="转入股票" tabindex="-1">转入股票 <a class="header-anchor" href="#转入股票" aria-label="Permalink to &quot;转入股票&quot;">​</a></h2><h3 id="操作流程" tabindex="-1">操作流程 <a class="header-anchor" href="#操作流程" aria-label="Permalink to &quot;操作流程&quot;">​</a></h3><ol><li>长桥 App - 资产 - 全部功能 - 存入股票 - 提交股票转入申请</li><li>填写转出券商、股票代码和转入数量</li><li>确认详细信息后提交，注册邮箱将收到具体指引</li><li>联系转出券商告知转仓，确认后点击「已联系」</li></ol><h3 id="成本价说明" tabindex="-1">成本价说明 <a class="header-anchor" href="#成本价说明" aria-label="Permalink to &quot;成本价说明&quot;">​</a></h3><p>每股成本价为选填项：</p><ul><li>未填写：成本价按实际转仓成功当日收盘价计算</li><li>已填写：转仓成功后盈亏按填写的成本价计算</li></ul><h3 id="转入注意事项" tabindex="-1">转入注意事项 <a class="header-anchor" href="#转入注意事项" aria-label="Permalink to &quot;转入注意事项&quot;">​</a></h3><ul><li>只有「待提交」状态才能修改申请，「执行中」状态需重新提交</li><li>取消转仓申请需双方券商同时取消</li></ul><hr><h2 id="转出股票" tabindex="-1">转出股票 <a class="header-anchor" href="#转出股票" aria-label="Permalink to &quot;转出股票&quot;">​</a></h2><h3 id="操作流程-1" tabindex="-1">操作流程 <a class="header-anchor" href="#操作流程-1" aria-label="Permalink to &quot;操作流程&quot;">​</a></h3><ol><li>长桥 App - 资产 - 全部功能 - 转出股票 - 提交股票转出申请</li><li>填写接收券商信息和股票信息后提交</li><li>通知接收券商通过长桥转出方信息中的邮件/电话与长桥确认指示与交割时间</li><li>双方券商收到客户相同指示后操作完成转仓</li></ol><h3 id="转出-otc-股票" tabindex="-1">转出 OTC 股票 <a class="header-anchor" href="#转出-otc-股票" aria-label="Permalink to &quot;转出 OTC 股票&quot;">​</a></h3><p>App 内不支持转出 OTC 股票。如需转出：</p><ol><li>发送转出申请至 <a href="mailto:contact@longbridge.sg" target="_blank" rel="noreferrer">contact@longbridge.sg</a></li><li>向接收券商提交股票转入指令</li></ol><h3 id="转出注意事项" tabindex="-1">转出注意事项 <a class="header-anchor" href="#转出注意事项" aria-label="Permalink to &quot;转出注意事项&quot;">​</a></h3><ul><li>仅支持同名转仓（NCBO），暂不支持变更受益人转仓</li><li>账户处于融资中或不足转仓手续费将无法发起转出</li><li>持仓股票需结算完成才可提交转出</li><li>转仓过程中如遇股票派息，长桥收到股息后会入账至客户长桥账户</li></ul><hr><h2 id="interactive-brokers-转仓说明" tabindex="-1">Interactive Brokers 转仓说明 <a class="header-anchor" href="#interactive-brokers-转仓说明" aria-label="Permalink to &quot;Interactive Brokers 转仓说明&quot;">​</a></h2><p>经由 IB（盈透）转仓时，需在 IB 端提交申请后联系长桥客服提供 IB 方转仓订单编号（Reference Number）。在 IB 填写接收账户时，请填写长桥 SG 开头的证券账号，不要填写 UID。</p>',28)])])}const f=e(i,[["render",o]]);export{b as __pageData,f as default};
